function getTeam(name) {
  if (TEAMS_DATA[name]) return TEAMS_DATA[name];
  const nl = name.toLowerCase();
  for (const k of Object.keys(TEAMS_DATA)) {
    if (k.toLowerCase() === nl) return TEAMS_DATA[k];
  }
  return null;
}
function getPlayers(teamName) {
  if (PLAYERS_DATA[teamName]) return PLAYERS_DATA[teamName];
  const nl = teamName.toLowerCase();
  for (const k of Object.keys(PLAYERS_DATA)) {
    if (k.toLowerCase() === nl) return PLAYERS_DATA[k];
  }
  return [];
}
function getLogoUrl(teamName) {
  const id = ESPN_LOGO_IDS[teamName];
  return id ? `https://a.espncdn.com/i/teamlogos/ncaa/500/${id}.png` : null;
}
